package Day0312;

public class 수증가하기함수 {
	//기능 : 수증가 시키기
	//입력 : 수
	//반환 : 증가된 수
	public static int 수증가하기(int index) {
		for(int i = 0; i< 5; i++) {
			index++;
		}
		return index;
	}
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int result = 수증가하기(0);
		System.out.println(result);
		//수증가 
		
		//수증가
		
	}
}
